@font-face {
  font-family: 'CustomWebFont';
  src: url('/fonts/CustomWebFont-Regular.woff2') format('woff2'),
       url('/fonts/CustomWebFont-Regular.woff') format('woff');
  font-weight: 400;
  font-style: normal;
  font-display: swap; /* Crucial for better UX and perceived performance */
}

body {
  font-family: 'CustomWebFont', 'Helvetica Neue', Helvetica, Arial, sans-serif;
  line-height: 1.5;
  color: #222;
}
